'use client';

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { doc, getDoc, collection, addDoc, getDocs, query, where, setDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Project } from '@/lib/types';
import BottomNav from '@/components/BottomNav';

interface Application {
  id: string;
  candidateId: string;
  candidateCodeName: string;
  coverNote: string;
  status: string;
  appliedAt: string;
  compatibilityScore?: number;
  chatId?: string;
}

interface CandidateMeta {
  uid: string;
  score: number;
  metadata: Record<string, unknown>;
  justification?: string;
  concerns?: string | null;
}

export default function ProjectDetailPage() {
  const { id } = useParams<{ id: string }>();
  const { user, profile } = useAuth();
  const router = useRouter();

  const [project, setProject] = useState<Project | null>(null);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState<'overview' | 'applicants' | 'candidates'>('overview');
  const [applications, setApplications] = useState<Application[]>([]);
  const [candidates, setCandidates] = useState<CandidateMeta[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [applyNote, setApplyNote] = useState('');
  const [showApplyModal, setShowApplyModal] = useState(false);
  const [applied, setApplied] = useState(false);
  const [loadingAction, setLoadingAction] = useState(false);
  const [toast, setToast] = useState<string | null>(null);

  const isOwner = user?.uid === project?.ownerId;

  useEffect(() => {
    if (!id) return;
    (async () => {
      const snap = await getDoc(doc(db, 'projects', id));
      if (snap.exists()) setProject({ id: snap.id, ...snap.data() } as Project);
      setLoading(false);
    })();
  }, [id]);

  useEffect(() => {
    if (!id || !user) return;
    getDocs(query(collection(db, 'applications'), where('projectId', '==', id), where('candidateId', '==', user.uid)))
      .then((s) => { if (!s.empty) setApplied(true); });
  }, [id, user]);

  const loadApplications = async () => {
    if (!id) return;
    const snap = await getDocs(query(collection(db, 'applications'), where('projectId', '==', id)));
    setApplications(snap.docs.map((d) => ({ id: d.id, ...d.data() } as Application)));
  };

  const loadRecommendedCandidates = async () => {
    if (!project) return;
    try {
      const projectText = `${project.name}. ${project.description}. Skills: ${(project.desiredSkills ?? project.tags ?? []).join(', ')}`;
      const res = await fetch('/api/pinecone', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'search-candidates', payload: { projectText, topK: 20 } }),
      });
      const { matches } = await res.json();
      if (!matches?.length) { setCandidates([]); return; }

      // Rerank with NIM
      const rerankRes = await fetch('/api/nim', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'rerank-candidates',
          payload: { candidates: matches, projectContext: `${project.name}: ${project.description}`, topK: 10 },
        }),
      });
      const { ranked } = await rerankRes.json();
      const rankedMap = new Map((ranked ?? []).map((r: { uid: string; justification: string; concerns: string | null }) => [r.uid, r]));
      const merged = matches.map((m: CandidateMeta) => ({ ...m, ...(rankedMap.get(m.uid) as object ?? {}) }));
      setCandidates(merged.slice(0, 10));
    } catch { setCandidates([]); }
  };

  const handleTabChange = async (t: 'overview' | 'applicants' | 'candidates') => {
    setTab(t);
    if (t === 'applicants' && applications.length === 0) await loadApplications();
    if (t === 'candidates' && candidates.length === 0) await loadRecommendedCandidates();
  };

  const handleApply = async () => {
    if (!user || !profile || !project) return;
    setLoadingAction(true);
    const chatId = [user.uid, project.ownerId].sort().join(`_proj_${id}_`);
    try {
      const appData = {
        projectId: id, projectName: project.name,
        ownerId: project.ownerId, ownerCodeName: project.ownerCodeName,
        candidateId: user.uid, candidateCodeName: profile.codeName,
        coverNote: applyNote, status: 'pending',
        compatibilityScore: 0, chatId,
        appliedAt: new Date().toISOString(), updatedAt: new Date().toISOString(),
      };
      await addDoc(collection(db, 'applications'), appData);

      // Create chat thread
      await setDoc(doc(db, 'chats', chatId), {
        id: chatId, type: 'individual',
        participants: [user.uid, project.ownerId],
        participantNames: { [user.uid]: profile.codeName, [project.ownerId]: project.ownerCodeName },
        projectId: id, projectName: project.name,
        lastMessage: applyNote || `${profile.codeName} applied to ${project.name}`,
        lastMessageAt: new Date().toISOString(), createdAt: new Date().toISOString(),
      });

      // Auto-send cover note as first message
      if (applyNote) {
        await addDoc(collection(db, 'messages'), {
          chatId, senderId: user.uid, senderCodeName: profile.codeName,
          text: applyNote, timestamp: new Date().toISOString(), type: 'text',
        });
      }
      await addDoc(collection(db, 'messages'), {
        chatId, senderId: 'system', senderCodeName: 'System',
        text: `${profile.codeName} applied to "${project.name}"`,
        timestamp: new Date().toISOString(), type: 'system',
      });

      setApplied(true);
      setShowApplyModal(false);
      setToast('Application sent! The owner will see your message ✓');
    } catch (err) { console.error(err); }
    finally { setLoadingAction(false); }
  };

  const messageCandidate = (candidateId: string, candidateCodeName: string) => {
    if (!user || !profile) return;
    const chatId = [user.uid, candidateId].sort().join(`_proj_${id}_`);
    router.push(`/chat?open=${chatId}&name=${encodeURIComponent(candidateCodeName)}`);
  };

  const filteredApps = applications.filter((a) =>
    !searchQuery || a.candidateCodeName.toLowerCase().includes(searchQuery.toLowerCase()) ||
    a.coverNote.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const filteredCandidates = candidates.filter((c) =>
    !searchQuery ||
    String(c.metadata.codeName ?? '').toLowerCase().includes(searchQuery.toLowerCase()) ||
    (c.metadata.hard_skills as string[] ?? []).some((s: string) => s.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  if (loading) return <div className="loading-page"><div className="spinner" /></div>;
  if (!project) return (
    <div className="loading-page" style={{ flexDirection: 'column', gap: 12 }}>
      <div style={{ fontSize: 32 }}>🔍</div>
      <p style={{ color: 'var(--subtle)' }}>Project not found</p>
      <button className="back-btn" onClick={() => router.push('/projects')}>← Back to projects</button>
    </div>
  );

  return (
    <div className="app-shell">
      <header className="c-header">
        <button className="back-btn" onClick={() => router.push('/projects')}>←</button>
        <span className="c-logo" style={{ fontSize: 16 }}>{project.name}</span>
      </header>

      {/* Tab bar — owner sees all 3, candidate sees overview only */}
      <div style={{ display: 'flex', borderBottom: '1px solid var(--border)' }}>
        {(['overview', ...(isOwner ? ['applicants', 'candidates'] : [])] as Array<'overview' | 'applicants' | 'candidates'>).map((t) => (
          <button key={t} onClick={() => handleTabChange(t)}
            style={{
              flex: 1, padding: '12px 4px', fontSize: 11, textTransform: 'uppercase', letterSpacing: '0.5px',
              border: 'none', background: 'none', cursor: 'pointer',
              color: tab === t ? 'var(--white)' : 'var(--muted)',
              borderBottom: tab === t ? '2px solid var(--white)' : '2px solid transparent',
              fontWeight: tab === t ? 600 : 400,
            }}>
            {t === 'applicants' ? `Applicants (${applications.length})` : t.charAt(0).toUpperCase() + t.slice(1)}
          </button>
        ))}
      </div>

      <div className="page-content" style={{ padding: '16px 16px 100px' }}>

        {/* ── OVERVIEW ──────────────────────────────────────────────────────── */}
        {tab === 'overview' && (
          <>
            <div className="pc-badge" style={{ marginBottom: 12, display: 'inline-block' }}>
              {project.isHackathon ? '⚡ Hackathon' : project.category}
            </div>
            <p style={{ fontSize: 14, color: 'var(--subtle)', lineHeight: 1.7, fontWeight: 300, marginBottom: 16 }}>
              {project.description}
            </p>
            <div className="pc-tags" style={{ marginBottom: 16 }}>
              {(project.desiredSkills ?? project.tags ?? []).map((t: string) => (
                <span key={t} className="pc-tag">{t}</span>
              ))}
            </div>
            <div className="score-row">
              <div className="score-item">
                <span className="score-num">{project.teamSize}</span>
                <span className="score-lbl">Team Size</span>
              </div>
              {project.commitmentHours && (
                <div className="score-item">
                  <span className="score-num">{project.commitmentHours}h</span>
                  <span className="score-lbl">Per Week</span>
                </div>
              )}
              <div className="score-item">
                <span className="score-num">{project.approvedUsers?.length ?? 0}</span>
                <span className="score-lbl">Members</span>
              </div>
            </div>
            {project.workingStylePace && (
              <div style={{ margin: '16px 0', padding: '12px 14px', background: 'var(--dark)', border: '1px solid var(--border)', borderRadius: 12 }}>
                <div style={{ fontSize: 10, textTransform: 'uppercase', letterSpacing: 1, color: 'var(--muted)', marginBottom: 4 }}>Working Style</div>
                <div style={{ fontSize: 13 }}>
                  {project.workingStylePace === 'hackathon' ? '⚡ Hackathon sprint' :
                    project.workingStylePace === 'short-term' ? '🔥 Short-term build' : '🏗 Long-term project'}
                </div>
              </div>
            )}
            <div style={{ borderTop: '1px solid var(--border)', paddingTop: 16, marginTop: 8 }}>
              <div style={{ fontSize: 12, color: 'var(--subtle)' }}>by {project.ownerCodeName}</div>
            </div>

            {!isOwner && (
              <button
                className="auth-btn"
                style={{ marginTop: 20 }}
                disabled={applied}
                onClick={() => !applied && setShowApplyModal(true)}
              >
                {applied ? '✓ Applied' : 'Apply to Join →'}
              </button>
            )}
            {isOwner && (
              <button className="edit-profile-btn" style={{ marginTop: 20 }}
                onClick={() => handleTabChange('applicants')}>
                View Applicants →
              </button>
            )}
          </>
        )}

        {/* ── APPLICANTS (owner only) ────────────────────────────────────────── */}
        {tab === 'applicants' && (
          <>
            <input
              className="chat-input"
              style={{ width: '100%', borderRadius: 12, marginBottom: 16 }}
              placeholder="Search by name or keyword..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            {filteredApps.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '40px 0', color: 'var(--subtle)' }}>
                {applications.length === 0 ? 'No applications yet.' : 'No results for your search.'}
              </div>
            ) : filteredApps.map((app) => (
              <div key={app.id} className="project-card" style={{ marginBottom: 12 }}>
                <div className="pc-top">
                  <div>
                    <div className="chat-name">{app.candidateCodeName}</div>
                    <div style={{ fontSize: 11, color: 'var(--muted)' }}>
                      Applied {new Date(app.appliedAt).toLocaleDateString()}
                    </div>
                  </div>
                  <div className={`pc-badge ${app.status === 'accepted' ? 'hackathon' : ''}`}>{app.status}</div>
                </div>
                {app.coverNote && (
                  <p style={{ fontSize: 13, color: 'var(--subtle)', fontStyle: 'italic', margin: '8px 0 12px' }}>
                    &ldquo;{app.coverNote}&rdquo;
                  </p>
                )}
                <button
                  className="interested-btn"
                  onClick={() => messageCandidate(app.candidateId, app.candidateCodeName)}
                >
                  Message
                </button>
              </div>
            ))}
          </>
        )}

        {/* ── RECOMMENDED CANDIDATES (owner only) ───────────────────────────── */}
        {tab === 'candidates' && (
          <>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}>
              <div>
                <div className="section-title" style={{ fontSize: 18 }}>Recommended</div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 2 }}>
                  <span className="nim-badge">✦ AI Matched</span>
                  <span style={{ fontSize: 11, color: 'var(--muted)' }}>Semantic + compatibility</span>
                </div>
              </div>
              <button onClick={loadRecommendedCandidates} className="filter-chip" style={{ cursor: 'pointer', height: 'fit-content' }}>
                Refresh
              </button>
            </div>
            <input
              className="chat-input"
              style={{ width: '100%', borderRadius: 12, marginBottom: 16 }}
              placeholder="Filter by skill, name..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            {candidates.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '40px 0', color: 'var(--subtle)' }}>
                <div style={{ fontSize: 36, marginBottom: 12 }}>🔍</div>
                <p>Add your Pinecone API key to enable AI candidate search.</p>
              </div>
            ) : filteredCandidates.map((c, i) => (
              <div key={c.uid} className="project-card">
                <div className="pc-top">
                  <div style={{ flex: 1 }}>
                    <div className="chat-name">{String(c.metadata.codeName ?? 'Anonymous')}</div>
                    <div style={{ fontSize: 11, color: 'var(--muted)' }}>{String(c.metadata.college ?? '')}</div>
                  </div>
                  <div style={{ textAlign: 'right' }}>
                    <div style={{ fontSize: 16, fontFamily: 'var(--font-dm-serif)' }}>#{i + 1}</div>
                    <div style={{ fontSize: 10, color: 'var(--muted)' }}>{((c.score ?? 0) * 100).toFixed(0)}% match</div>
                  </div>
                </div>

                <div className="pc-tags" style={{ margin: '8px 0 10px' }}>
                  {(c.metadata.hard_skills as string[] ?? []).slice(0, 4).map((s: string) => (
                    <span key={s} className="pc-tag">{s}</span>
                  ))}
                </div>

                {c.justification && (
                  <div className="nim-insight" style={{ margin: '0 0 10px' }}>
                    <span><span className="nim-badge">✦ Why they fit</span></span>
                    {c.justification}
                    {c.concerns && <span style={{ color: '#ff9966', display: 'block', marginTop: 4 }}>⚠ {c.concerns}</span>}
                  </div>
                )}

                <button
                  className="interested-btn"
                  onClick={() => messageCandidate(c.uid, String(c.metadata.codeName ?? 'Candidate'))}
                >
                  Invite to Chat
                </button>
              </div>
            ))}
          </>
        )}
      </div>

      {/* Apply Modal */}
      {showApplyModal && (
        <div style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.85)', zIndex: 100,
          display: 'flex', alignItems: 'flex-end', justifyContent: 'center',
        }}>
          <div style={{
            background: 'var(--dark)', border: '1px solid var(--border)', borderRadius: '20px 20px 0 0',
            padding: 24, width: '100%', maxWidth: 430,
          }}>
            <div style={{ fontFamily: 'var(--font-dm-serif)', fontSize: 22, marginBottom: 6 }}>Apply to Join</div>
            <div style={{ fontSize: 13, color: 'var(--subtle)', marginBottom: 16 }}>{project.name}</div>
            <textarea
              className="chat-input"
              style={{ width: '100%', borderRadius: 12, minHeight: 80, resize: 'none', marginBottom: 16, fontFamily: 'var(--font-dm-sans)' }}
              placeholder="Add a short note (optional) — it becomes your first message to the owner..."
              value={applyNote}
              onChange={(e) => setApplyNote(e.target.value)}
            />
            <button className="auth-btn" onClick={handleApply} disabled={loadingAction}>
              {loadingAction ? 'Sending...' : 'Send Application →'}
            </button>
            <button className="auth-link" style={{ marginTop: 12, width: '100%' }} onClick={() => setShowApplyModal(false)}>
              Cancel
            </button>
          </div>
        </div>
      )}

      {toast && <div className="toast">{toast}</div>}
      <BottomNav />
    </div>
  );
}
